import React, { useState } from 'react';
import { motion } from 'framer-motion';

function Contact() {
  const [form, setForm] = useState({ nom: '', email: '', sujet: '', message: '' });
  const [envoye, setEnvoye] = useState(false);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = (e) => {
    e.preventDefault();
    setEnvoye(true);
    setTimeout(() => setEnvoye(false), 4000);
  };

  return (
    <div style={{ background: '#000000', minHeight: '100vh', paddingTop: '100px' }}>
      <motion.section
        initial={{ opacity: 0, y: -30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
        style={{
          textAlign: 'center', padding: '60px 20px',
          background: 'radial-gradient(ellipse at center, #0a1a0a 0%, #000000 70%)',
          borderBottom: '2px solid #00aa00'
        }}
      >
        <h1 style={{ fontSize: '48px', color: '#ffd700', letterSpacing: '4px', marginBottom: '15px' }}>Contact</h1>
        <p style={{ color: '#aaaaaa', fontSize: '18px' }}>Parlons de votre projet informatique</p>
      </motion.section>

      <section style={{ padding: '80px 50px', maxWidth: '1100px', margin: '0 auto' }}>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '40px' }}>

          {/* INFOS */}
          <motion.div
            initial={{ opacity: 0, x: -50 }}
            whileInView={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.8 }}
          >
            <h2 style={{ color: '#ffd700', fontSize: '28px', marginBottom: '30px' }}>Mes coordonnées</h2>
            {[
              { icon: '📍', titre: 'Localisation', info: 'Dakar, Sénégal\nQuartier Fass Delorme, 10500' },
              { icon: '📧', titre: 'Email', info: 'badjinaboussougourevesyndie@gmail.com' },
              { icon: '🕐', titre: 'Sur site — Dakar', info: 'Lundi — Vendredi : 08h00 - 18h00' },
              { icon: '🌐', titre: 'À distance', info: 'Lundi — Samedi : Disponible à toute heure' }
            ].map((item, i) => (
              <motion.div
                key={i}
                whileHover={{ x: 10 }}
                style={{
                  display: 'flex', gap: '15px', marginBottom: '25px',
                  background: '#0a0a0a', border: '1px solid #00aa00',
                  borderRadius: '12px', padding: '20px'
                }}
              >
                <span style={{ fontSize: '30px' }}>{item.icon}</span>
                <div>
                  <h3 style={{ color: '#00aa00', fontSize: '16px', marginBottom: '5px' }}>{item.titre}</h3>
                  <p style={{ color: '#cccccc', fontSize: '14px', whiteSpace: 'pre-line' }}>{item.info}</p>
                </div>
              </motion.div>
            ))}
          </motion.div>

          {/* FORMULAIRE */}
          <motion.div
            initial={{ opacity: 0, x: 50 }}
            whileInView={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.8 }}
            style={{
              background: '#0a0a0a', border: '1px solid #00aa00',
              borderRadius: '15px', padding: '40px'
            }}
          >
            <h2 style={{ color: '#ffd700', fontSize: '28px', marginBottom: '30px' }}>Envoyez un message</h2>

            {envoye && (
              <motion.div
                initial={{ opacity: 0, scale: 0.8 }}
                animate={{ opacity: 1, scale: 1 }}
                style={{
                  background: '#00aa00', color: '#ffffff',
                  padding: '15px', borderRadius: '10px',
                  textAlign: 'center', marginBottom: '20px', fontSize: '15px'
                }}
              >
                ✅ Message envoyé ! Je vous répondrai rapidement.
              </motion.div>
            )}

            <div>
              {[
                { name: 'nom', placeholder: 'Votre nom complet', type: 'text' },
                { name: 'email', placeholder: 'Votre adresse email', type: 'email' },
                { name: 'sujet', placeholder: 'Sujet de votre message', type: 'text' }
              ].map((field) => (
                <input
                  key={field.name}
                  type={field.type}
                  name={field.name}
                  placeholder={field.placeholder}
                  value={form[field.name]}
                  onChange={handleChange}
                  style={{
                    width: '100%', padding: '12px 15px', marginBottom: '15px',
                    background: '#1a1a1a', border: '1px solid #333333',
                    borderRadius: '8px', color: '#ffffff', fontSize: '14px',
                    outline: 'none', boxSizing: 'border-box'
                  }}
                />
              ))}
              <textarea
                name="message"
                placeholder="Décrivez votre projet..."
                value={form.message}
                onChange={handleChange}
                rows={5}
                style={{
                  width: '100%', padding: '12px 15px', marginBottom: '20px',
                  background: '#1a1a1a', border: '1px solid #333333',
                  borderRadius: '8px', color: '#ffffff', fontSize: '14px',
                  outline: 'none', resize: 'vertical', boxSizing: 'border-box'
                }}
              />
              <motion.button
                whileHover={{ scale: 1.05, boxShadow: '0 0 20px #00aa00' }}
                whileTap={{ scale: 0.95 }}
                onClick={handleSubmit}
                style={{
                  width: '100%', padding: '15px',
                  background: '#00aa00', color: '#ffffff',
                  border: 'none', borderRadius: '10px',
                  fontSize: '16px', fontWeight: 'bold', cursor: 'pointer'
                }}
              >
                Envoyer le message 🚀
              </motion.button>
            </div>
          </motion.div>
        </div>
      </section>
    </div>
  );
}

export default Contact;
